import { Component, Event, EventEmitter, h, Prop } from '@stencil/core';
import { Item } from '@src/utils/mx-utils/calendar-service';

@Component({
  tag: 'mx-picker-pill',
  shadow: false
})
export class MxPickerPill {
  /** Sets the filter type to be used in CSS classes and the input id. */
  @Prop() readonly filtersType: string;
  /** Sets the disabled status. */
  @Prop() readonly filterDisable: boolean;
  /** Sets the dropdown disabled status. */
  @Prop() readonly dropdownDisable: boolean;
  /** Sets active status. */
  @Prop() readonly isActive: boolean;
  /** Sets the label for the pill. */
  @Prop() readonly pillLabel: string;
  /** Sets items array. */
  @Prop() readonly items: Item[];
  /** Sets the selected item. */
  @Prop() readonly selectedItem: Item;

  /** Event emitted when an item is updated. */
  @Event() updateItem: EventEmitter<MouseEvent>;
  /** Event emitted when a filter is toggled. */
  @Event() toggleFilter: EventEmitter<MouseEvent>;

  private handleItemChange = (event) => {
    event.preventDefault();
    this.updateItem.emit(event.detail);
  };

  private _toggleFilter = (event) => {
    event.preventDefault();
    this.toggleFilter.emit(event);
  };

  render() {
    return (
      <div class='mx-picker-pill' aria-label={`picker ${this.filtersType}`}>
        <button
          class={{
            [`mx-picker-filter ${this.filtersType}-filter`]: true,
            [`border border-neutral-less-prominent`]: true,
            [`bg-primary text-brand-less-prominent 
              hover:bg-secondary`]: !this.filterDisable && !this.isActive,
            [`active-filter bg-brand-less-prominent text-primary-inverse 
              hover:bg-primary hover:text-brand-less-prominent`]: this.isActive && !this.filterDisable,
            'bg-quaternary-fill text-secondary': this.filterDisable
          }}
          disabled={this.filterDisable}
          onClick={this._toggleFilter}>
          <span class={`pill-label ${this.filtersType}-filter`}>{this.pillLabel}</span>
        </button>
        <mx-single-select
          input-id={`${this.filtersType}-dropdown`}
          isDisabled={this.dropdownDisable}
          items={this.items}
          itemSelected={this.selectedItem}
          is-compact={true}
          place-holder='--'
          width='85px'
          onItemChange={this.handleItemChange}
          list-width='100%'></mx-single-select>
      </div>
    );
  }
}
