import { Component, Event, EventEmitter, h, Prop } from '@stencil/core';

@Component({
  tag: 'mx-time-switcher'
})
export class MxTimeSwitcher {
  /** Sets time picker data to appropriate calendar dates (Fiscal: Sun-Sat, Ad: Wed-Tues) */
  @Prop() readonly calType: 'fiscal' | 'ad' = 'fiscal';

  /** Disables the radio buttons */
  @Prop() readonly disabled: boolean = false;

  /** Event emitted whenever the calendar is updated */
  @Event() updateCal: EventEmitter<any>;

  private readonly emitOnInput = (type: 'fiscal' | 'ad') =>
    (e: InputEvent) => this.updateCal.emit({ event: e, type });

  render() {
    return (
      <span class='mx-radio-group mx-time-switcher-wrapper'>
        <kds-label class='mx-radio-label'>
          <kds-radio
            class='mx-cal-radio'
            disabled={this.disabled}
            name='mx-cal-group'
            checked={this.calType === 'fiscal'}
            onInput={this.emitOnInput('fiscal')}
            value='fiscal'></kds-radio>
          Fiscal
        </kds-label>

        <kds-label class='mx-radio-label'>
          <kds-radio
            class='mx-cal-radio'
            disabled={this.disabled}
            name='mx-cal-group'
            checked={this.calType === 'ad'}
            onInput={this.emitOnInput('ad')}
            value='ad'></kds-radio>
          Ad
        </kds-label>
      </span>
    );
  }
}
